var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으, 눈부셔.","JPN":"うう、眩しい。","ENG":"Ugh... The flashes are hurting my eyes.","TWN":"呃，太刺眼了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_ENERGY_BIG_06"},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"검의 움직임을 눈으로 좇는 것도 버거울 정도야.","JPN":"剣の動きを目で追うことで精一杯だ。","ENG":"It's hard to follow their sword movements with the naked eye.","TWN":"靠肉眼已經有些跟不上劍的速度了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저 모르스라는 그림자, 과거엔 얼마나 강한 카운터였던 거지?","JPN":"あのモールスというシャドウ、過去ではどれほど強いカウンターだったんだろうね？","ENG":"That Shadow, Mors, I wonder how powerful she was when she was a Counter.","TWN":"那個叫死神的暗影，過去究竟是多麼強大的制裁者？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아직도 일어서는 건가?","JPN":"まだ立ち上がるのか？","ENG":"Still getting back up?","TWN":"你還能站起來嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온을 쓰러트리기 전까지 난 쓰러지지 않는다.","JPN":"タギリオンを倒すまで我は倒れん。","ENG":"I will not fall before Thagirion is defeated.","TWN":"在打敗塔基里翁之前，我不會倒下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그런 뻔한 거짓말을 하다니.","JPN":"そのような見え透いた嘘をつくとは。","ENG":"Again with your lies.","TWN":"滿口謊言。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"죄인만이 걸치는 그 갑주를 내가 못 알아볼 거라 생각하나?","JPN":"罪人だけが身に着けるその鎧を我が知らないとでも思ったのか？","ENG":"Did you think I would fail to realize that your armor is only for sinners?","TWN":"以為我認不出你那只有罪人才能穿上的盔甲？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내 앞을 가로막는 죄수의 말을 신용할 가치는 없다.","JPN":"我の行く手を阻む罪人の言葉に信用の価値などない。","ENG":"I do not trust the words coming from a sinner who is blocking my path.","TWN":"一個擋我路的罪人說的話不值得相信。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너의 존재가… 타기리온을 불러들이고 있으니…","JPN":"そなたの存在が……タギリオンを呼び寄せている……","ENG":"Your existence... is what is summoning Thagirion...","TWN":"你的出現……正在召喚塔基里翁……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는 그저 막을 뿐이다.","JPN":"我はただ、防ぐだけだ。","ENG":"And I am here to stop that.","TWN":"我只想阻止她。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"끝났군요.","JPN":"終わりましたね。","ENG":"It is over.","TWN":"結束了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타기리온이 현실을 완전히 잠식하면, 당신이 지금껏 해온 노력은 모두 허사가 되겠죠.","JPN":"タギリオンが現実を完全に侵食すると、今までのあなたの努力は全部無駄になるでしょう。","ENG":"Once Thagirion completely consumes this world, everything you have done up until this moment will be in vain.","TWN":"一旦塔基里翁徹底吞噬了現世，你所有的努力都將付諸東流。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"감상이 어떠신가요?","JPN":"どんなお気持ちですか？","ENG":"How does that make you feel?","TWN":"不知你有何感想？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파 차원을 틀어막는 방주의 에너지는 애초부터 무한하지 않았네.","JPN":"クリファ次元を封じ込めている箱舟のエネルギーは最初から無限ではなかったのだ。","ENG":"The Ark's energy that's blocking the Qlipha Dimension has never been infinite.","TWN":"方舟用來阻止逆卡巴拉次元的能量本來就不是無限的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"언젠가 닥칠 일이란 건 알았지만, 조금 이르다는 감은 있군.","JPN":"いつかはこうなると思っていたが、少し早い気がするな。","ENG":"This was going to happen sooner or later, but it feels a little earlier than I had expected.","TWN":"我早就料到她回來，但比我的預期有些早而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저런 꼴을 보고서도 아직 포기를 못한 건가요?","JPN":"あのありさまを見てもまだ、諦めがつかないのですか？","ENG":"You still have hope, after seeing what has happened?","TWN":"看到這些還沒有放棄嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"할 수 있는 데까진 해봐야지.","JPN":"やれるところまではやってみるさ。","ENG":"I need to do what I can.","TWN":"我會盡我所能。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어느정도 예상했던… 지극히 당신다운 대답이긴 하군요.","JPN":"ある程度は予想していた……極めてあなたらしい答えですね。","ENG":"That is... very much what someone like you would say, as expected.","TWN":"預料之中的回答……很像你的作風。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 지금 기적이 일어나 봉인을 틀어막는다 해도, 태엽을 감은 타기리온이 현실에 강림하는 건 시간 문제일 뿐입니다.","JPN":"しかし今奇跡が起きてまた封印したとしても、タギリオンのねじは巻かれました。現実に降臨するのはもはや時間の問題です。","ENG":"Even if, by some miracle, you stop the seal from breaking, Thagirion's spring has been wound. It's only a matter of time before she emerges into the Normalside.","TWN":"即使現在發生奇蹟阻止封印解開，塔基里翁的降臨也只是時間問題。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다고 남은 시간을 체념만 하며 보낼 순 없지 않겠나.","JPN":"だからと言って残っている時間をただ諦めて過ごすわけにはいかないだろう。","ENG":"That doesn't mean I should waste whatever precious time I have left.","TWN":"但總不想垂頭喪氣地等死吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 세계에 와일드카드는 많지만, 지금 당장 꺼낼 수 있는 건 없어요.","JPN":"あなたの世界にワイルドカードは多いですが、今使えるカードはないはずです。","ENG":"There are a lot of wildcards in your world, but none you can play right now.","TWN":"就算你的世界裡有很多幫手，但在這裡卻一個也派不上用場。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"늑대는 상처를 입어 제 실력을 발휘하지 못하고, 대적자는 빼앗은 마왕의 권능을 갈무리하고 있으며, 발키리는 기억을 되찾기 위해 아케론으로 향했죠.","JPN":"狼は怪我を負い戦力外になり、敵対者は奪った魔王の権能を収束しているところ、ヴァルキリーは記憶を取り戻すためにアケロンへ向かいましたね。","ENG":"The Wolf is wounded and not in her best shape to fight, the Antagonist is wrestling with the power of the Demon Lord that he stole, and the Valkyrie has headed to Acheron to retrieve her lost memories.","TWN":"狼受了傷，無法發揮出最佳狀態，對敵者正在收割她奪取的魔王之力，，而女武神則前往黃泉找回自己的記憶。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타기리온에 대적할 운명인 아발론의 후손들과 시무르그의 파편 또한 침식으로부터 당장 주변의 인명을 지키기 위해 발이 묶여 있습니다.","JPN":"タギリオンに敵対する運命であるアバロンの末裔とシムルグの破片も同じく、周りの人々を侵食から守るために動けない状態です。","ENG":"The descendants of Avalon and the fragment of Simurgh, who were fated to fight Thagirion, are also tied up trying to protect people from Corruption.","TWN":"命中註定與塔基里翁對抗的阿瓦隆的後裔和西摩格的碎片，現在也只能忙著保護周圍人的安全。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신 혼자서 요술이라도 부릴 셈인가요?","JPN":"あなた一人で魔法でも使うつもりですか？","ENG":"So, are you planning on performing some kind of magic on your own?","TWN":"你一個人還能使出什麼花樣？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나 혼자선 아무것도 바꿀 수 있는 게 없네.","JPN":"私一人では何も変えられない。","ENG":"There is nothing I can do alone to change anything.","TWN":"我一個人無法改變任何事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 알다시피, 평범한 인간이니까.","JPN":"君もご存じのとおり、私はただの人間だからね。","ENG":"As you know, I'm just an ordinary human.","TWN":"如你所見，我只是個普通人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 지금 당신을 이곳에 가둬놓아도 별 의미는 없는 것 같네요.","JPN":"今あなたをここに閉じ込めておくのも大した意味はなさそうですね。","ENG":"It seems that there is no use keeping you in here right now.","TWN":"我覺得現在把你困在這裡也沒什麼意義。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"잠시 객석에서 일어나는 것 정도는 허락해드리죠.","JPN":"少しの間客席から立つことを許可しましょう。","ENG":"I shall grant you an intermission.","TWN":"我允許你暫時離開觀眾席。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님!","JPN":"社長！","ENG":"Boss!","TWN":"老闆！"},"stage":{"bg":"WHITE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내 목소리가 들린다면 이쪽으로 와줘!","JPN":"私の声が聞こえるならこっちに来て！","ENG":"If you can hear my voice, head toward it!","TWN":"如果你能聽到我說話，請到我這邊！"},"stage":{"bg":"WHITE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"손을 뻗는다","JPN":"手を伸ばす","ENG":"Reach out hand","TWN":"伸出手"},"stage":{"bg":"WHITE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아앗! 정말로 성공했어요!","JPN":"ああっ！　本当に成功しました！","ENG":"Oh! It really worked!","TWN":"哇！成功了！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"안녕하세요! 사장님! 무사하신가요?","JPN":"こんにちは！　社長！　ご無事ですか？","ENG":"Hi! Boss! Are you all right?","TWN":"老闆你好！老闆沒事吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"우선 여기서 나가자! 훼방꾼이 올지도 몰라!","JPN":"まず、ここから出よう！　邪魔が入るかもしれない！","ENG":"Let's get out of here first! The saboteur could come any second!","TWN":"我們快離開這裡！敵人馬上要攻過來了！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"타기리온의 시선이 이미 하늘을 잠식하고 있군.","JPN":"タギリオンの視線が既に空を侵食しているな。","ENG":"Thagirion's eyes have already consumed the sky.","TWN":"塔基里翁的視線已經開始侵蝕天空。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님을 찾긴 했지만 이제 어쩌죠?","JPN":"社長を見つけましたけど、これからどうしましょう？","ENG":"We found Boss, but what do we do now?","TWN":"雖然找到了老闆，但接下來怎麼辦？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"스완은 모르스의 거울을 통해 열쇠를 이 세계로 끌어들였어.","JPN":"スワンはモールスの鏡を通じて鍵をこの世界へ持ってきた。","ENG":"Swan used Mors' mirror to bring the key to our world.","TWN":"史旺透過死神之鏡將鑰匙帶到了這個世界。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 존재는 클리파를 이용한만큼 불안정하고 일시적이지.","JPN":"しかしその存在はクリファを利用している分、不安定で一時的なものだ。","ENG":"But because it was brought using Qilpha, it's temporary and unstable.","TWN":"但因為使用了逆卡巴拉，她的存在不穩定且不永久。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파의 유입을 차단하기만 하면, 거울은 효력을 잃고 사라질 걸세.","JPN":"クリファの流入を遮断できれば、鏡は効力を失い消えるだろう。","ENG":"If we cut off the inflow of Qilpha, the mirror will also lose its effectiveness and disappear.","TWN":"只要阻斷逆卡巴拉的流入，鏡子就會失去效果並且消失。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼, 봉인을 다시 틀어막을 수단이 있다는 거지? 어떻게 하면 되는데?","JPN":"そしたら、もう一度封印する手段があるということだね？　どうすればいいんだ？","ENG":"So, there is a way to seal her off again? What do we need to do?","TWN":"這麼說還有辦法阻止封印解開？我們該怎麼做？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들은 늘 그래왔던대로 최선을 다해 싸워주면 된다네.","JPN":"君たちはいつものように最善を尽くして戦ってくれればそれでいいんだ。","ENG":"What you have always been doing. Fight with everything you've got.","TWN":"你們只需和之前一樣全力戰鬥。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다행히 지원군이 너무 늦지 않게 도착해줬군.","JPN":"幸い支援軍が遅れずに到着したようだ。","ENG":"Fortunately for us, our reinforcements aren't that late.","TWN":"幸運的是，援軍也及時抵達了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"살다 살다 이런 일로 목숨까지 걸게 될 줄은 몰랐는데.","JPN":"まさか、こんなことで命をかけることになるとは思わなかったけど。","ENG":"Didn't think the day would come for me to risk my life like this.","TWN":"沒想到我自己會為這種事賭上性命。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"이렇게만 하면 관리국 정식 스폰서 계약, 틀림없겠죠?","JPN":"これで管理局と正式なスポンサー契約、できるんですよね？","ENG":"We get our official Administration sponsorship by doing this, right?","TWN":"這樣一定可以得到管理局的正式贊助約吧？"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러엄, 서류도 이미 확인했잖아?","JPN":"もちろん、書類も確認しただろう？","ENG":"Of course! You already checked the paperwork.","TWN":"當然了，你不是已經檢查過檔案嗎？"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"모두에게 보여주라고. 네가 가장 잘 할 수 있는 걸.","JPN":"みんなに見せるんだ。あんたが得意なことを。","ENG":"It's time to show everyone what you can do best.","TWN":"向大家展示一下你最擅長的東西。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"후우…","JPN":"ふう……","ENG":"Huu...","TWN":"呼……"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"안녕. 샤레이드…","JPN":"こんにちは、シャレード……","ENG":"Hello, Charade...","TWN":"哈囉，查雷德……"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아니, 관리국 재난방송을 보고 있는 전세계의 시청자 여러분!","JPN":"いいえ、管理局の災難放送を見ている世界中の皆さん！","ENG":"I mean, people all over the world watching the Administration disaster broadcast!","TWN":"不，收看管理局災難廣播的全世界各地的觀眾！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"난 일일 중계를 맡게 된 샤레이드의 베티 미치!","JPN":"私は今日中継を担当することになったシャレードのベティー・ミッチー！","ENG":"I'm your host for the day, Batty Mitchie from Charade!","TWN":"我是來自查雷德的貝蒂·米琪，是今天的主持人！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그리고 내가 있는 이곳은, 지금 벌어지고 있는 대규모 침식사태의 근원지야!","JPN":"そして私がいるここは、今起こっている大規模な侵食事態の根源地だよ！","ENG":"The place where I'm right now is... none other than the source of the large-scale Corruption disaster!","TWN":"我目前在大規模侵蝕事件的根源地！"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};